import { Routes } from '@angular/router';
import { VehiculeListe } from './vehicule-liste/vehicule-liste';
import { VehiculeNew } from './vehicule-new/vehicule-new';
import { authorizationGuard } from '@/guards/authorization.guard';

export default [
  {
    path: '',
    component: VehiculeListe,
    canActivate: [authorizationGuard],
    data: { permissions: ['vehicules.read'] },
  },
  {
    path: 'nouveau',
    component: VehiculeNew,
    canActivate: [authorizationGuard],
    data: { permissions: ['vehicules.create'] },
  },
  { path: '**', redirectTo: '/notfound' },
] as Routes;
