import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import {
  AbstractControl,
  FormBuilder,
  FormGroup,
  ReactiveFormsModule,
  ValidationErrors,
  Validators,
} from '@angular/forms';
import { MessageService } from 'primeng/api';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { InputNumberModule } from 'primeng/inputnumber';
import { ToastModule } from 'primeng/toast';
import { DividerModule } from 'primeng/divider';
import { CardModule } from 'primeng/card';

import { VehiculeService } from '@/services/vehicules/vehicule.service';

/** Validateur cross-field : part_proprietaire + part_livreur doit = 100 */
export function commissionSumValidator(group: AbstractControl): ValidationErrors | null {
  const pp = +(group.get('part_proprietaire')?.value ?? 0);
  const pl = +(group.get('part_livreur')?.value ?? 0);
  return pp + pl === 100 ? null : { commissionTotal: true };
}

@Component({
  selector: 'app-vehicule-new',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    ReactiveFormsModule,
    ButtonModule,
    InputTextModule,
    InputNumberModule,
    ToastModule,
    DividerModule,
    CardModule,
  ],
  providers: [MessageService],
  templateUrl: './vehicule-new.html',
})
export class VehiculeNew implements OnInit {
  form!: FormGroup;
  loading = false;
  photoFile: File | null = null;
  photoPreview: string | null = null;

  constructor(
    private fb: FormBuilder,
    private vehiculeService: VehiculeService,
    private messageService: MessageService,
    private router: Router
  ) {}

  ngOnInit() {
    this.form = this.fb.group(
      {
        // ── Véhicule
        marque: ['', [Validators.required, Validators.maxLength(100)]],
        modele: ['', [Validators.required, Validators.maxLength(100)]],
        immatriculation: ['', [Validators.required, Validators.maxLength(50)]],
        // ── Propriétaire
        proprietaire_nom: ['', Validators.required],
        proprietaire_prenom: ['', Validators.required],
        proprietaire_telephone: ['', Validators.required],
        proprietaire_email: ['', Validators.email],
        proprietaire_adresse: [''],
        // ── Livreur
        livreur_nom: ['', Validators.required],
        livreur_prenom: ['', Validators.required],
        livreur_telephone: ['', Validators.required],
        livreur_email: ['', Validators.email],
        // ── Commission
        part_proprietaire: [50, [Validators.required, Validators.min(0), Validators.max(100)]],
        part_livreur: [50, [Validators.required, Validators.min(0), Validators.max(100)]],
      },
      { validators: commissionSumValidator }
    );
  }

  // ── Photo ─────────────────────────────────────────────────────────────
  onPhotoChange(event: Event) {
    const file = (event.target as HTMLInputElement).files?.[0];
    if (!file) return;
    this.photoFile = file;
    const reader = new FileReader();
    reader.onload = () => (this.photoPreview = reader.result as string);
    reader.readAsDataURL(file);
  }

  removePhoto() {
    this.photoFile = null;
    this.photoPreview = null;
  }

  // ── Helpers ───────────────────────────────────────────────────────────
  field(name: string) {
    return this.form.get(name)!;
  }

  isInvalid(name: string): boolean {
    const c = this.form.get(name)!;
    return c.invalid && (c.dirty || c.touched);
  }

  get commissionTotal(): number {
    return +(this.field('part_proprietaire').value ?? 0) + +(this.field('part_livreur').value ?? 0);
  }

  get commissionValid(): boolean {
    return this.commissionTotal === 100;
  }

  // ── Soumission ────────────────────────────────────────────────────────
  onSubmit() {
    this.form.markAllAsTouched();
    if (this.form.invalid) return;
    if (!this.photoFile) {
      this.messageService.add({
        severity: 'warn',
        summary: 'Photo requise',
        detail: 'Veuillez sélectionner une photo du véhicule.',
        life: 4000,
      });
      return;
    }

    const v = this.form.value;
    const fd = new FormData();

    // Véhicule
    fd.append('marque', v.marque);
    fd.append('modele', v.modele);
    fd.append('immatriculation', v.immatriculation);
    fd.append('photo', this.photoFile);

    // Propriétaire
    fd.append('proprietaire_nom', v.proprietaire_nom);
    fd.append('proprietaire_prenom', v.proprietaire_prenom);
    fd.append('proprietaire_telephone', v.proprietaire_telephone);
    if (v.proprietaire_email) fd.append('proprietaire_email', v.proprietaire_email);
    if (v.proprietaire_adresse) fd.append('proprietaire_adresse', v.proprietaire_adresse);

    // Livreur
    fd.append('livreur_nom', v.livreur_nom);
    fd.append('livreur_prenom', v.livreur_prenom);
    fd.append('livreur_telephone', v.livreur_telephone);
    if (v.livreur_email) fd.append('livreur_email', v.livreur_email);

    // Commission
    fd.append('part_proprietaire', String(v.part_proprietaire));
    fd.append('part_livreur', String(v.part_livreur));

    this.loading = true;
    this.vehiculeService.createOneShot(fd).subscribe({
      next: () => {
        this.loading = false;
        this.messageService.add({
          severity: 'success',
          summary: 'Succès',
          detail: 'Véhicule créé avec succès.',
          life: 3000,
        });
        setTimeout(() => this.router.navigate(['/vehicules']), 1500);
      },
      error: (err) => {
        this.loading = false;
        this.handleApiError(err);
      },
    });
  }

  onCancel() {
    this.router.navigate(['/vehicules']);
  }

  private handleApiError(err: any) {
    if (err.status === 422 && err.error?.errors) {
      const msgs = Object.values(err.error.errors).flat() as string[];
      msgs.forEach((m) =>
        this.messageService.add({
          severity: 'error',
          summary: 'Erreur de validation',
          detail: m,
          life: 5000,
        })
      );
    } else if (err.status === 403) {
      this.messageService.add({
        severity: 'error',
        summary: 'Accès refusé',
        detail: 'Vous n\'avez pas les permissions nécessaires.',
        life: 5000,
      });
    } else if (err.status === 409) {
      this.messageService.add({
        severity: 'warn',
        summary: 'Conflit',
        detail: err.error?.message || 'Ce véhicule existe déjà.',
        life: 5000,
      });
    } else {
      this.messageService.add({
        severity: 'error',
        summary: 'Erreur',
        detail: err.error?.message || 'Une erreur est survenue.',
        life: 5000,
      });
    }
  }
}
