import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { MessageService } from 'primeng/api';
import { TableModule, Table } from 'primeng/table';
import { ButtonModule } from 'primeng/button';
import { ToastModule } from 'primeng/toast';
import { ToolbarModule } from 'primeng/toolbar';
import { InputTextModule } from 'primeng/inputtext';
import { SkeletonModule } from 'primeng/skeleton';
import { TagModule } from 'primeng/tag';
import { TooltipModule } from 'primeng/tooltip';
import { InputIconModule } from 'primeng/inputicon';
import { IconFieldModule } from 'primeng/iconfield';

import { VehiculeService } from '@/services/vehicules/vehicule.service';
import { Vehicule } from '@/models/vehicule.model';
import { AuthService } from '@/services/auth/auth.service';

@Component({
  selector: 'app-vehicule-liste',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    TableModule,
    ButtonModule,
    ToastModule,
    ToolbarModule,
    InputTextModule,
    SkeletonModule,
    TagModule,
    TooltipModule,
    InputIconModule,
    IconFieldModule,
  ],
  providers: [MessageService],
  templateUrl: './vehicule-liste.html',
})
export class VehiculeListe implements OnInit {
  vehicules = signal<Vehicule[]>([]);
  loading = false;
  canCreate = false;

  constructor(
    private vehiculeService: VehiculeService,
    private messageService: MessageService,
    private authService: AuthService,
    private router: Router
  ) {
    this.canCreate = this.authService.hasPermission('vehicules.create');
  }

  ngOnInit() {
    this.loadVehicules();
  }

  loadVehicules() {
    this.loading = true;
    this.vehiculeService.getVehicules().subscribe({
      next: (resp) => {
        this.vehicules.set(Array.isArray(resp.data) ? resp.data : []);
        this.loading = false;
      },
      error: () => {
        this.messageService.add({
          severity: 'error',
          summary: 'Erreur',
          detail: 'Impossible de charger les véhicules',
          life: 3000,
        });
        this.loading = false;
      },
    });
  }

  goNew() {
    this.router.navigate(['/vehicules/nouveau']);
  }

  onGlobalFilter(table: Table, event: Event) {
    table.filterGlobal((event.target as HTMLInputElement).value, 'contains');
  }

  formatDate(dateStr: string): string {
    if (!dateStr) return '';
    return new Date(dateStr).toLocaleDateString('fr-FR');
  }

  getInitials(v: Vehicule): string {
    return `${v.marque?.charAt(0) ?? ''}${v.modele?.charAt(0) ?? ''}`.toUpperCase();
  }
}
